const rows = $input.all();

if (rows.length === 0) {
  return [];
}

// row_number が一番大きい行を取得
const lastRow = rows.sort((a, b) => {
  return Number(a.json.row_number) - Number(b.json.row_number);
}).at(-1);

// row_number 以外の値を取り出す
const values = Object.entries(lastRow.json)
  .filter(([key, value]) => key !== 'row_number')
  .map(([key, value]) => value)
  .filter(value => value !== null && value !== undefined && String(value).trim() !== '');

// URLらしい値を取得
const url = values.find(value => {
  return String(value).startsWith('http://') || String(value).startsWith('https://');
});

return [
  {
    json: {
      row_number: lastRow.json.row_number,
      url: url || ''
    }
  }
];

// ======================================================
// AI: Polish Japanese Translationで整えた日本語 text と
// AssemblyAI の words から
// 日本語字幕JSON配列と Creatomate用RenderScriptを作成する Code ノード
//
// 対応内容：
// - 字幕は基本的に1行で表示する
// - 長い字幕は自然な文章区切りで分割する
// - 最後の字幕は必ず AssemblyAI words の最後の end で終わる
// ======================================================


// ======================================================
// 1. AI: Polish Japanese Translation の出力を取得
// ======================================================

const llmInput = items[0].json;


// ======================================================
// 2. AssemblyAI GET結果の元データを取得
// ======================================================

const originalNodeName = 'Check: AssemblyAI Transcript Status';

let originalInput;

try {
  originalInput = $(originalNodeName).item.json;
} catch (error) {
  originalInput = $(originalNodeName).first().json;
}

if (!originalInput || Object.keys(originalInput).length === 0) {
  throw new Error(
    `元データを取得できませんでした。ノード名「${originalNodeName}」が正しいか確認してください。`
  );
}


// ======================================================
// 3. AI: Polish Japanese Translation の出力から整形済み text を取得
// ======================================================

function pickTextFromObject(obj) {
  if (!obj || typeof obj !== 'object') {
    return '';
  }

  const directKeys = [
    'text',
    'output',
    'response',
    'result',
    'content',
    'chat_message',
    'completion'
  ];

  for (const key of directKeys) {
    if (typeof obj[key] === 'string' && obj[key].trim() !== '') {
      return obj[key];
    }
  }

  if (
    obj.message &&
    typeof obj.message.content === 'string' &&
    obj.message.content.trim() !== ''
  ) {
    return obj.message.content;
  }

  if (obj.data && typeof obj.data === 'object') {
    const textFromData = pickTextFromObject(obj.data);

    if (textFromData) {
      return textFromData;
    }
  }

  if (obj.output && typeof obj.output === 'object') {
    const textFromOutput = pickTextFromObject(obj.output);

    if (textFromOutput) {
      return textFromOutput;
    }
  }

  if (Array.isArray(obj.generations)) {
    const firstGeneration = obj.generations[0];

    if (firstGeneration) {
      if (
        typeof firstGeneration.text === 'string' &&
        firstGeneration.text.trim() !== ''
      ) {
        return firstGeneration.text;
      }

      if (
        firstGeneration.message &&
        typeof firstGeneration.message.content === 'string' &&
        firstGeneration.message.content.trim() !== ''
      ) {
        return firstGeneration.message.content;
      }
    }
  }

  return '';
}

let formattedText = pickTextFromObject(llmInput);


// ======================================================
// 4. AI: Polish Japanese Translation の出力が取れない場合は AssemblyAI 翻訳を補助的に使う
// ======================================================

if (
  !formattedText &&
  originalInput.translated_texts &&
  typeof originalInput.translated_texts.ja === 'string' &&
  originalInput.translated_texts.ja.trim() !== ''
) {
  formattedText = originalInput.translated_texts.ja;
}

formattedText = String(formattedText || '').trim();

formattedText = formattedText
  .replace(/^整形後の本文[:：]\s*/g, '')
  .replace(/^出力[:：]\s*/g, '')
  .replace(/^本文[:：]\s*/g, '')
  .replace(/^結果[:：]\s*/g, '')
  .trim();

if (!formattedText) {
  throw new Error(
    [
      'AI: Polish Japanese Translationの整形済みtextが取得できませんでした。',
      'また、AssemblyAIの translated_texts.ja も取得できませんでした。',
      'AI: Polish Japanese Translationの入力が {{ $json.translated_texts.ja }} になっているか確認してください。',
      '',
      '現在のAI: Polish Japanese Translation出力:',
      JSON.stringify(llmInput, null, 2),
      '',
      '現在のAssemblyAI出力:',
      JSON.stringify(originalInput, null, 2)
    ].join('\n')
  );
}


// ======================================================
// 5. textだけ AI: Polish Japanese Translation の出力に差し替える
// ======================================================

const input = {
  ...originalInput,
  text: formattedText,
  original_text_before_llm: originalInput.text || '',
  translated_ja_before_llm: originalInput.translated_texts?.ja || '',
  text_source: 'AI: Polish Japanese Translation or AssemblyAI translated_texts.ja',
  original_data_source: originalNodeName
};


// ======================================================
// 6. AssemblyAI の処理完了チェック
// ======================================================

if (input.status !== 'completed') {
  throw new Error(
    `AssemblyAIの文字起こしがまだ完了していません。現在のstatus: ${input.status}`
  );
}


// ======================================================
// 7. 字幕用の日本語 text を取得
// ======================================================

const textForSubtitle = String(input.text || '').trim();

if (!textForSubtitle) {
  throw new Error(
    'input.text が空です。日本語字幕用テキストが取得できていません。'
  );
}


// ======================================================
// 9. AssemblyAI の words を取得
// ======================================================

const words = input.words;

if (!Array.isArray(words) || words.length === 0) {
  throw new Error(
    'AssemblyAIの出力に words がありません。「Check: AssemblyAI Transcript Status」のOutputで words が配列になっているか確認してください。'
  );
}


// ======================================================
// 10. 動画URLを取得
// ======================================================

const videoUrl =
  input.audio_url ||
  input.video_url ||
  input.videoUrl ||
  input['動画URL'];

if (!videoUrl) {
  throw new Error(
    '動画URLが取得できません。audio_url / video_url / videoUrl / 動画URL のいずれかを確認してください。'
  );
}


// ======================================================
// 11. 記号・文字列処理用の設定
// ======================================================

const punctuationRegex = /[、。,.!?！？「」『』（）()\[\]【】]/g;

function normalizeText(text) {
  return String(text || '')
    .replace(punctuationRegex, '')
    .replace(/\s+/g, '')
    .trim();
}

function cleanDisplayText(text) {
  return String(text || '')
    .replace(punctuationRegex, '')
    .replace(/\s+/g, '')
    .trim();
}

function keepBreakText(text) {
  return String(text || '')
    .replace(/\s+/g, '')
    .trim();
}


// ======================================================
// 12. 文字種判定
// ======================================================

function isAsciiAlphaNumeric(char) {
  return /[A-Za-z0-9]/.test(char || '');
}

function isJapaneseChar(char) {
  return /[\u3040-\u30ff\u3400-\u9fff]/.test(char || '');
}

function isKatakanaChar(char) {
  return /[\u30a0-\u30ffー]/.test(char || '');
}

function isDigitChar(char) {
  return /[0-9０-９]/.test(char || '');
}

function isJapaneseNumberUnitChar(char) {
  return /[十百千万億兆]/.test(char || '');
}

function isBadJapaneseContinuation(previous, next) {
  const pair = `${previous || ''}${next || ''}`;

  const badPairs = [
    'でき',
    'きな',
    'なく',
    'くな',
    'なり',
    'なる',
    'ので',
    'です',
    'すが',
    'まし',
    'した',
    'して',
    'いる',
    'あり',
    'ませ',
    'せん',
    'わか',
    '分か',
    'かり',
    'りま',
    'ます',
    'こと',
    'とは',
    'には',
    'では'
  ];

  return badPairs.includes(pair);
}


// ======================================================
// 13. 字幕の調整値
// ======================================================
//
// ここでは、動画の向きに合わせて
// 「字幕1回あたりに表示する文字数」を自動で切り替える。
//
// 理由：
// 横長動画なら、画面の横幅が広いため少し長めの字幕でも読みやすい。
// 一方で、縦長動画は横幅が狭いため、長い字幕を出すと
// 画面上で折り返されたり、文字が詰まって見えたりしやすい。
//
// そのため、Fetch: Video Metadataノードの
// videoMediaMetadata.width
// videoMediaMetadata.height
// を確認し、height が width より大きい場合は「縦動画」と判断する。
//
// 縦動画の場合：
// - 最低文字数：6
// - 理想文字数：16
// - 通常上限：16
// - 絶対上限：16
//
// 横動画・またはサイズ取得できない場合：
// - これまで通りの設定を使う
// - 最低文字数：6
// - 理想文字数：16
// - 通常上限：22
// - 絶対上限：28
//
// ※ const ではなく let にしている理由：
// 動画の向きによって、あとから値を入れ替える必要があるため。
// ======================================================

const videoMetadataNodeName = 'Fetch: Video Metadata';

let videoMetadataInput;

try {
  videoMetadataInput = $(videoMetadataNodeName).item.json;
} catch (error) {
  videoMetadataInput = $(videoMetadataNodeName).first().json;
}

const videoWidth = Number(videoMetadataInput?.videoMediaMetadata?.width || 0);
const videoHeight = Number(videoMetadataInput?.videoMediaMetadata?.height || 0);

const isPortraitVideo =
  Number.isFinite(videoWidth) &&
  Number.isFinite(videoHeight) &&
  videoWidth > 0 &&
  videoHeight > 0 &&
  videoHeight > videoWidth;

let minCharsPerSubtitle = 6;
let idealCharsPerSubtitle = 16;
let maxCharsPerSubtitle = 22;
let hardMaxCharsPerSubtitle = 28;

if (isPortraitVideo) {
  minCharsPerSubtitle = 6;
  idealCharsPerSubtitle = 16;
  maxCharsPerSubtitle = 16;
  hardMaxCharsPerSubtitle = 16;
}


// ======================================================
// 14. 途中で切りたくない表現
// ======================================================

const protectedPhrases = [
  '理解できない',
  '全く理解できない',
  'できない',
  'できなく',
  'できなくなる',
  'できないでしょう',
  'できないでしょうから',
  'でしょうから',
  'でしょう',
  'でしょうか',
  'ありません',
  'ありませんでした',
  'していない',
  'していないでしょう',
  '持っていない',
  '持っていないでしょう',
  '始めたのですが',
  'テストを始めたのですが',
  '分かります',
  'わかります',
  '見舞われたこと',
  '見舞われたことが分かります',
  '文字起こし',
  '非常に時間がかかっていました',
  'そんなこと',
  '起こりません',
  'ダッシュボード',
  'ウェブアプリケーション',
  'ファイアウォール',
  'トラフィック',
  '正規のユーザー',
  'リクエスト',
  '毎分1万2千以上',
  '1万2千以上',
  '何億ものリクエスト',
  'BridgeVoice',
  'BridgeVoiceでは',
  'スキルセット',
  '中小企業',
  '大企業',
  '一部の大企業',
  'ビジネスマン',
  'AI副業',
  '人工知能',
  '動画編集',
  '自動化',
  '音声認識',
  '生成AI',
  'Googleスプレッドシート',
  'Googleスライド',
  'Googleドライブ',
  'n8n',
  'Creatomate',
  'AssemblyAI'
];

function isInsideProtectedPhrase(text, index) {
  if (index <= 0 || index >= text.length) {
    return false;
  }

  for (const phrase of protectedPhrases) {
    let searchStart = 0;

    while (true) {
      const foundIndex = text.indexOf(phrase, searchStart);

      if (foundIndex === -1) {
        break;
      }

      const phraseStart = foundIndex;
      const phraseEnd = foundIndex + phrase.length;

      if (index > phraseStart && index < phraseEnd) {
        return true;
      }

      searchStart = foundIndex + 1;
    }
  }

  return false;
}

function isBadSplitPosition(text, index) {
  if (index <= 0 || index >= text.length) {
    return false;
  }

  const prev = text[index - 1];
  const next = text[index];

  const before = cleanDisplayText(text.slice(0, index));
  const after = cleanDisplayText(text.slice(index));

  if (
    (before.endsWith('ウェブアプリケーション') && after.startsWith('ファイアウォール')) ||
    (before.endsWith('BridgeVoiceでは') && after.startsWith('そんなこと')) ||
    (before.endsWith('アクセス') && after.startsWith('できなく'))
  ) {
    return false;
  }

  if (isAsciiAlphaNumeric(prev) && isAsciiAlphaNumeric(next)) {
    return true;
  }

  if (isKatakanaChar(prev) && isKatakanaChar(next)) {
    return true;
  }

  if (isDigitChar(prev) && isJapaneseNumberUnitChar(next)) {
    return true;
  }

  if (isJapaneseNumberUnitChar(prev) && isDigitChar(next)) {
    return true;
  }

  if (isBadJapaneseContinuation(prev, next)) {
    return true;
  }

  if (isInsideProtectedPhrase(text, index)) {
    return true;
  }

  return false;
}


// ======================================================
// 15. 分割候補の評価
// ======================================================

const goodEndingPatterns = [
  'です',
  'ます',
  'でした',
  'ました',
  'でしょう',
  'ください',
  'できます',
  'できません',
  'ありません',
  'しています',
  'している',
  'していない',
  'になります',
  'ということです',
  'ということ',
  'という',
  'ため',
  'から',
  'なら',
  'には',
  'では',
  'とは',
  'こそ',
  'まで',
  'ほど',
  'だけ',
  'など',
  'もの'
];

const badEndingPatterns = [
  '理解で',
  '全く理解で',
  'でき',
  'できな',
  'できないで',
  'でし',
  'ので',
  'ょう',
  'しょう',
  'ダッシュボ',
  'ウェブアプリケーションファ',
  'ファ',
  'ファイ',
  'ファイア',
  'ファイアウ',
  'アクセスで',
  '1万2',
  '毎分1万2',
  'スキル',
  'セット',
  'そういったことの',
  'そういったことを',
  '一部の',
  'そのような',
  'どれも',
  '全く'
];

const badStartingPatterns = [
  'ード',
  'きない',
  'きなく',
  'きなくなる',
  '千以上',
  'が分かります',
  'がわかります',
  'すが',
  'ないでしょう',
  'でしょうから',
  'しょうから',
  'セット',
  '企業では',
  '部の大企業',
  'ういった',
  'れも',
  '解できない',
  '理解できない'
];

const connectorStartingPatterns = [
  '実は',
  '特に',
  '結論から',
  'では',
  'なぜ',
  'その理由',
  '一つ目',
  '二つ目',
  '三つ目',
  'まず',
  '次に',
  'さらに',
  'そして',
  'しかし',
  '例えば',
  '今回',
  '今すぐ',
  'これにより',
  'つまり',
  'そのため',
  '大切なのは',
  'ここで',
  'このように',
  'だから',
  '一方で'
];

const preferredStartingPatterns = [
  'ダッシュボード',
  '見舞われた',
  '見舞われたこと',
  '文字起こし',
  'BridgeVoiceでは',
  'そんなこと',
  'ファイアウォール',
  'トラフィック',
  'できなく',
  'できなくなる',
  'リクエスト',
  '昨日',
  '実際には',
  'この攻撃',
  '正規のユーザー',
  'すぐに'
];

const preferredEndingPatterns = [
  '簡単な',
  'リクエストに',
  '始めたのですが',
  'BridgeVoiceでは',
  'ウェブアプリケーション',
  'アクセス',
  '1万2千以上の',
  '毎分1万2千以上の'
];

function endsWithAny(text, patterns) {
  return patterns.some((pattern) => text.endsWith(pattern));
}

function startsWithAny(text, patterns) {
  return patterns.some((pattern) => text.startsWith(pattern));
}

function getSplitScore(text, index) {
  if (index <= 0 || index >= text.length) {
    return -9999;
  }

  if (isBadSplitPosition(text, index)) {
    return -9999;
  }

  const beforeRaw = text.slice(0, index);
  const afterRaw = text.slice(index);

  const before = cleanDisplayText(beforeRaw);
  const after = cleanDisplayText(afterRaw);

  if (before.length < minCharsPerSubtitle || after.length < minCharsPerSubtitle) {
    return -200;
  }

  if (endsWithAny(before, badEndingPatterns)) {
    return -800;
  }

  if (startsWithAny(after, badStartingPatterns)) {
    return -800;
  }

  let score = 0;

  const prev = text[index - 1];
  const next = text[index];

  if (
    prev === '。' ||
    prev === '！' ||
    prev === '？' ||
    prev === '!' ||
    prev === '?'
  ) {
    score += 120;
  }

  if (
    prev === '、' ||
    prev === ',' ||
    prev === ' ' ||
    prev === '　'
  ) {
    score += 100;
  }

  if (startsWithAny(after, preferredStartingPatterns)) {
    score += 150;
  }

  if (endsWithAny(before, preferredEndingPatterns)) {
    score += 150;
  }

  if (startsWithAny(afterRaw, connectorStartingPatterns)) {
    score += 80;
  }

  if (endsWithAny(before, goodEndingPatterns)) {
    score += 70;
  }

  if (
    prev === 'は' ||
    prev === 'が' ||
    prev === 'を' ||
    prev === 'に' ||
    prev === 'で' ||
    prev === 'へ' ||
    prev === 'も' ||
    prev === 'と' ||
    prev === 'や'
  ) {
    score += 35;
  }

  if (prev === 'の') {
    score += 10;
  }

  if (prev === 'な' && startsWithAny(after, preferredStartingPatterns)) {
    score += 60;
  }

  if (isAsciiAlphaNumeric(prev) && isJapaneseChar(next)) {
    score += 20;
  }

  if (isJapaneseChar(prev) && isAsciiAlphaNumeric(next)) {
    score += 20;
  }

  const distanceFromIdeal = Math.abs(before.length - idealCharsPerSubtitle);
  score -= distanceFromIdeal * 2;

  if (before.length > maxCharsPerSubtitle) {
    score -= 50;
  }

  return score;
}


// ======================================================
// 16. 安全で自然な分割位置を探す
// ======================================================

function findNaturalSplitIndex(text, preferredIndex = idealCharsPerSubtitle) {
  const rawText = String(text || '');

  if (cleanDisplayText(rawText).length <= maxCharsPerSubtitle) {
    return rawText.length;
  }

  const length = rawText.length;
  let bestIndex = -1;
  let bestScore = -9999;

  const searchStart = Math.max(minCharsPerSubtitle, preferredIndex - 10);
  const searchEnd = Math.min(length - minCharsPerSubtitle, hardMaxCharsPerSubtitle + 8);

  for (let i = searchStart; i <= searchEnd; i++) {
    const score = getSplitScore(rawText, i);

    if (score > bestScore) {
      bestScore = score;
      bestIndex = i;
    }
  }

  if (bestIndex !== -1 && bestScore > -100) {
    return bestIndex;
  }

  for (
    let i = Math.min(length - minCharsPerSubtitle, maxCharsPerSubtitle);
    i >= minCharsPerSubtitle;
    i--
  ) {
    const score = getSplitScore(rawText, i);

    if (score > -100) {
      return i;
    }
  }

  for (
    let i = maxCharsPerSubtitle + 1;
    i <= Math.min(length - minCharsPerSubtitle, hardMaxCharsPerSubtitle + 8);
    i++
  ) {
    const score = getSplitScore(rawText, i);

    if (score > -100) {
      return i;
    }
  }

  let fallbackIndex = Math.min(maxCharsPerSubtitle, length - minCharsPerSubtitle);

  while (
    fallbackIndex > minCharsPerSubtitle &&
    isBadSplitPosition(rawText, fallbackIndex)
  ) {
    fallbackIndex--;
  }

  if (fallbackIndex <= minCharsPerSubtitle) {
    fallbackIndex = Math.min(maxCharsPerSubtitle, length - minCharsPerSubtitle);

    while (
      fallbackIndex < length - minCharsPerSubtitle &&
      isBadSplitPosition(rawText, fallbackIndex)
    ) {
      fallbackIndex++;
    }
  }

  return fallbackIndex;
}


// ======================================================
// 17. LLM整形済みtextを、句読点ベースで大きく分ける
// ======================================================

function splitFormattedTextIntoSegments(text) {
  const segments = [];
  let buffer = '';

  for (let i = 0; i < text.length; i++) {
    const char = text[i];

    buffer += char;

    const isStrongBreak =
      char === '。' ||
      char === '！' ||
      char === '？' ||
      char === '!' ||
      char === '?';

    const isWeakBreak =
      char === '、' ||
      char === ',';

    const currentText = keepBreakText(buffer);
    const cleanedBuffer = cleanDisplayText(buffer);

    if (isStrongBreak) {
      if (cleanedBuffer.length > 0) {
        segments.push({
          text: currentText,
          break_type: 'strong'
        });
      }

      buffer = '';
      continue;
    }

    if (isWeakBreak && cleanedBuffer.length >= idealCharsPerSubtitle) {
      segments.push({
        text: currentText,
        break_type: 'weak'
      });

      buffer = '';
      continue;
    }

    if (cleanedBuffer.length >= hardMaxCharsPerSubtitle + 6) {
      const splitIndex = findNaturalSplitIndex(currentText, idealCharsPerSubtitle);
      const before = currentText.slice(0, splitIndex);
      const after = currentText.slice(splitIndex);

      if (cleanDisplayText(before).length > 0) {
        segments.push({
          text: before,
          break_type: 'length'
        });
      }

      buffer = after;
      continue;
    }
  }

  const rest = keepBreakText(buffer);

  if (cleanDisplayText(rest).length > 0) {
    segments.push({
      text: rest,
      break_type: 'end'
    });
  }

  return segments;
}


// ======================================================
// 18. 長いセグメントを自然な1行字幕に分割する
// ======================================================

function splitLongSegment(segmentText) {
  let current = String(segmentText || '');
  const result = [];

  if (cleanDisplayText(current).length <= maxCharsPerSubtitle) {
    const cleaned = cleanDisplayText(current);

    if (cleaned) {
      return [cleaned];
    }

    return [];
  }

  let safetyCounter = 0;

  while (cleanDisplayText(current).length > maxCharsPerSubtitle && safetyCounter < 100) {
    safetyCounter++;

    const splitIndex = findNaturalSplitIndex(current, idealCharsPerSubtitle);

    if (splitIndex <= 0 || splitIndex >= current.length) {
      break;
    }

    const before = cleanDisplayText(current.slice(0, splitIndex));
    const after = keepBreakText(current.slice(splitIndex));

    if (before.length > 0) {
      result.push(before);
    }

    current = after;

    if (!current) {
      break;
    }
  }

  const rest = cleanDisplayText(current);

  if (rest.length > 0) {
    result.push(rest);
  }

  return result;
}


// ======================================================
// 19. 不自然な分割を後処理で修復する
// ======================================================

function shouldMergeBecauseUnnatural(previous, current) {
  if (!previous || !current) {
    return false;
  }

  const merged = previous + current;

  if (merged.length > hardMaxCharsPerSubtitle) {
    return false;
  }

  if (endsWithAny(previous, badEndingPatterns)) {
    return true;
  }

  if (startsWithAny(current, badStartingPatterns)) {
    return true;
  }

  if (isAsciiAlphaNumeric(previous[previous.length - 1]) && isAsciiAlphaNumeric(current[0])) {
    return true;
  }

  if (isKatakanaChar(previous[previous.length - 1]) && isKatakanaChar(current[0])) {
    return true;
  }

  if (isDigitChar(previous[previous.length - 1]) && isJapaneseNumberUnitChar(current[0])) {
    return true;
  }

  if (previous.endsWith('理解で') && current.startsWith('きない')) {
    return true;
  }

  if (previous.endsWith('でき') && current.startsWith('ない')) {
    return true;
  }

  if (previous.endsWith('でき') && current.startsWith('なく')) {
    return true;
  }

  if (previous.endsWith('で') && current.startsWith('きなく')) {
    return true;
  }

  if (previous.endsWith('ので') && current.startsWith('すが')) {
    return true;
  }

  if (previous.endsWith('こと') && current.startsWith('が分かります')) {
    return true;
  }

  if (previous.endsWith('ダッシュボ') && current.startsWith('ード')) {
    return true;
  }

  if (previous.endsWith('ファ') && current.startsWith('イアウォール')) {
    return true;
  }

  if (previous.endsWith('1万2') && current.startsWith('千以上')) {
    return true;
  }

  if (previous.endsWith('スキル') && current.startsWith('セット')) {
    return true;
  }

  return false;
}

function repairUnnaturalSplits(texts) {
  const repaired = [];

  for (const rawText of texts) {
    const text = cleanDisplayText(rawText);

    if (!text) {
      continue;
    }

    if (repaired.length === 0) {
      repaired.push(text);
      continue;
    }

    const previous = repaired[repaired.length - 1];

    if (shouldMergeBecauseUnnatural(previous, text)) {
      repaired[repaired.length - 1] = previous + text;
    } else {
      repaired.push(text);
    }
  }

  return repaired;
}


// ======================================================
// 20. 短すぎる字幕を自然な範囲で結合する
// ======================================================

function mergeTooShortSegments(texts) {
  const result = [];

  for (const rawText of texts) {
    const text = cleanDisplayText(rawText);

    if (!text) {
      continue;
    }

    if (result.length === 0) {
      result.push(text);
      continue;
    }

    const previous = result[result.length - 1];
    const merged = previous + text;

    if (text.length < minCharsPerSubtitle && merged.length <= maxCharsPerSubtitle) {
      result[result.length - 1] = merged;
      continue;
    }

    if (
      previous.length < minCharsPerSubtitle &&
      merged.length <= maxCharsPerSubtitle
    ) {
      result[result.length - 1] = merged;
      continue;
    }

    result.push(text);
  }

  return result;
}


// ======================================================
// 21. 1行に収まるように最終調整する
// ======================================================

function forceOneLineButNatural(texts) {
  const result = [];

  for (const rawText of texts) {
    let current = cleanDisplayText(rawText);

    if (!current) {
      continue;
    }

    if (current.length <= hardMaxCharsPerSubtitle) {
      result.push(current);
      continue;
    }

    let safetyCounter = 0;

    while (current.length > hardMaxCharsPerSubtitle && safetyCounter < 100) {
      safetyCounter++;

      const splitIndex = findNaturalSplitIndex(current, idealCharsPerSubtitle);

      if (splitIndex <= 0 || splitIndex >= current.length) {
        break;
      }

      const before = cleanDisplayText(current.slice(0, splitIndex));
      const after = cleanDisplayText(current.slice(splitIndex));

      if (before.length > 0) {
        result.push(before);
      }

      current = after;

      if (!current) {
        break;
      }
    }

    if (current.length > 0) {
      result.push(current);
    }
  }

  return result;
}


// ======================================================
// 22. 日本語textから字幕テキスト配列を作る
// ======================================================

const rawSegments = splitFormattedTextIntoSegments(textForSubtitle);

let targetSubtitleTexts = [];

for (const segment of rawSegments) {
  const parts = splitLongSegment(segment.text);

  for (const part of parts) {
    const cleaned = cleanDisplayText(part);

    if (cleaned.length > 0) {
      targetSubtitleTexts.push(cleaned);
    }
  }
}

targetSubtitleTexts = repairUnnaturalSplits(targetSubtitleTexts);
targetSubtitleTexts = mergeTooShortSegments(targetSubtitleTexts);
targetSubtitleTexts = forceOneLineButNatural(targetSubtitleTexts);
targetSubtitleTexts = repairUnnaturalSplits(targetSubtitleTexts);
targetSubtitleTexts = mergeTooShortSegments(targetSubtitleTexts);

if (targetSubtitleTexts.length === 0) {
  throw new Error(
    '日本語textから字幕区切りを作成できませんでした。textの内容を確認してください。'
  );
}


// ======================================================
// 23. AssemblyAI words から全体時間だけを取得する
// ======================================================
//
// ここでは words の text は字幕本文として使わない。
// words は「開始時刻」と「終了時刻」を取るためだけに使う。
// ======================================================

const cleanWords = [];

for (const word of words) {
  const cleanWord = normalizeText(word.text);

  if (!cleanWord) {
    continue;
  }

  if (
    typeof word.start !== 'number' ||
    typeof word.end !== 'number'
  ) {
    continue;
  }

  cleanWords.push({
    text: cleanWord,
    start: word.start,
    end: word.end
  });
}

if (cleanWords.length === 0) {
  throw new Error(
    'AssemblyAIのwordsをクリーン化した結果、使用できる単語がありませんでした。'
  );
}


// ======================================================
// 24. 日本語字幕を動画全体の時間に合わせて配置する
// ======================================================

const subtitles = [];

const totalStartMs = cleanWords[0].start || 0;
const totalEndMs = cleanWords[cleanWords.length - 1].end;

if (!Number.isFinite(totalEndMs) || totalEndMs <= totalStartMs) {
  throw new Error(
    `字幕の全体時間を取得できませんでした。totalStartMs=${totalStartMs}, totalEndMs=${totalEndMs}`
  );
}

const totalDurationMs = totalEndMs - totalStartMs;

const displayTexts = targetSubtitleTexts
  .map((text) => cleanDisplayText(text))
  .filter((text) => text && text.length > 0);

if (displayTexts.length === 0) {
  throw new Error(
    '日本語字幕テキストが空です。targetSubtitleTexts の中身を確認してください。'
  );
}

const totalChars = displayTexts.join('').length;

if (totalChars === 0) {
  throw new Error(
    '日本語字幕の合計文字数が0です。AI: Polish Japanese Translationの出力を確認してください。'
  );
}

const preferredMinDurationMs = 550;
const safeMinDurationMs = Math.min(
  preferredMinDurationMs,
  Math.floor(totalDurationMs / displayTexts.length)
);

let currentMs = totalStartMs;

for (let i = 0; i < displayTexts.length; i++) {
  const displayText = displayTexts[i];

  let startMs = currentMs;
  let endMs;

  if (i === displayTexts.length - 1) {
    endMs = totalEndMs;
  } else {
    const ratio = displayText.length / totalChars;
    let durationMs = totalDurationMs * ratio;

    durationMs = Math.max(durationMs, safeMinDurationMs);

    endMs = startMs + durationMs;

    const remainingCount = displayTexts.length - i - 1;
    const minimumRemainingMs = remainingCount * safeMinDurationMs;

    if (endMs > totalEndMs - minimumRemainingMs) {
      endMs = totalEndMs - minimumRemainingMs;
    }
  }

  if (endMs <= startMs) {
    endMs = Math.min(startMs + safeMinDurationMs, totalEndMs);
  }

  const durationMs = endMs - startMs;

  if (durationMs > 0) {
    subtitles.push({
      time: Number((startMs / 1000).toFixed(2)),
      duration: Number((durationMs / 1000).toFixed(2)),
      value: displayText
    });
  }

  currentMs = endMs;
}


// ======================================================
// 25. 最後の字幕が必ず totalEndMs で終わるように微調整
// ======================================================

if (subtitles.length > 0) {
  const last = subtitles[subtitles.length - 1];

  const lastStartMs = Math.round(last.time * 1000);
  const fixedLastDurationMs = totalEndMs - lastStartMs;

  if (fixedLastDurationMs > 0) {
    last.duration = Number((fixedLastDurationMs / 1000).toFixed(2));
  }
}


// ======================================================
// 26. 字幕が作成できなかった場合はエラー
// ======================================================

if (subtitles.length === 0) {
  throw new Error(
    '字幕データを作成できませんでした。targetSubtitleTexts または words の中身を確認してください。'
  );
}


// ======================================================
// 27. Creatomate用の字幕テキスト要素を作成
// ======================================================
//
// 1行表示を優先する。
// heightを小さくしすぎると上下が窮屈になるため、10%にする。
// 文字サイズは大きすぎると折り返しされやすいので5.5vminに調整。
// ======================================================

const subtitleElements = subtitles.map((subtitle) => {
  return {
    type: 'text',

    time: subtitle.time,
    duration: subtitle.duration,
    text: subtitle.value,

    x: '50%',
    y: '82%',

    width: '94%',
    height: '10%',

    x_alignment: '50%',
    y_alignment: '50%',

    fill_color: '#ffffff',
    stroke_color: '#000000',
    stroke_width: '1.1 vmin',

    font_family: 'Noto Sans JP',
    font_weight: 700,
    font_size: '5.5 vmin',

    background_color: 'rgba(0,0,0,0)',

    z_index: 10
  };
});


// ======================================================
// 28. Creatomate APIに送るBodyを作成
// ======================================================
//
// width / height を指定しないことで、元動画サイズのまま出力する。
// ======================================================

const creatomateBody = {
  output_format: 'mp4',

  elements: [
    {
      type: 'video',
      source: videoUrl,

      x: '50%',
      y: '50%',
      width: '100%',
      height: '100%',

      fit: 'contain',

      z_index: 1
    },

    ...subtitleElements
  ]
};


// ======================================================
// 29. 次のHTTP Requestノードに渡す
// ======================================================

return [
  {
    json: {
      video_url: videoUrl,

      subtitle_count: subtitles.length,
      subtitles,

      subtitle_timing_debug: {
        total_start_ms: totalStartMs,
        total_end_ms: totalEndMs,
        total_duration_sec: Number((totalDurationMs / 1000).toFixed(2)),
        min_chars_per_subtitle: minCharsPerSubtitle,
        ideal_chars_per_subtitle: idealCharsPerSubtitle,
        max_chars_per_subtitle: maxCharsPerSubtitle,
        hard_max_chars_per_subtitle: hardMaxCharsPerSubtitle,
        video_width: videoWidth,
        video_height: videoHeight,
        is_portrait_video: isPortraitVideo,
        last_subtitle_end_sec: Number(
          (
            subtitles[subtitles.length - 1].time +
            subtitles[subtitles.length - 1].duration
          ).toFixed(2)
        )
      },

      normalized_text_debug: {
        original_text: input.text,
        normalized_text: textForSubtitle
      },

      creatomate_body: creatomateBody
    }
  }
];
